package com.enterprise.banking.security;

import com.enterprise.banking.model.BankingTransaction;
import java.math.BigDecimal;
import java.util.Set;
import java.util.regex.Pattern;

public final class InputValidator {

    private static final Pattern ACCOUNT_PATTERN = Pattern.compile("^[A-Z]{2}\\d{2}[A-Z0-9]{4}\\d{7,25}$");
    private static final Pattern TRANSACTION_ID_PATTERN = Pattern.compile("^[a-f0-9\\-]{36}$");
    private static final Pattern DESCRIPTION_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s.,\\-]{0,200}$");
    private static final Set<String> ALLOWED_CURRENCIES = Set.of("USD", "EUR", "GBP", "CHF", "JPY", "CAD", "AUD");
    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("10000000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");

    private InputValidator() {}

    public static void validateTransaction(BankingTransaction transaction) {
        if (transaction == null) {
            throw new SecurityException("Transaction must not be null");
        }

        validateAccountNumber(transaction.getSourceAccount(), "Source account");
        validateAccountNumber(transaction.getDestinationAccount(), "Destination account");
        validateAmount(transaction.getAmount());
        validateCurrency(transaction.getCurrency());
        validateDescription(transaction.getDescription());
        validateTransactionId(transaction.getTransactionId());

        if (transaction.getSourceAccount().equals(transaction.getDestinationAccount())) {
            throw new SecurityException("Source and destination accounts must differ");
        }
    }

    public static void validateAccountNumber(String account, String fieldName) {
        if (account == null || account.isBlank()) {
            throw new SecurityException(fieldName + " is required");
        }
        if (!ACCOUNT_PATTERN.matcher(account).matches()) {
            throw new SecurityException(fieldName + " format is invalid (expected IBAN format)");
        }
    }

    public static void validateAmount(BigDecimal amount) {
        if (amount == null) {
            throw new SecurityException("Amount is required");
        }
        if (amount.compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
            throw new SecurityException("Amount must be at least " + MIN_TRANSACTION_AMOUNT);
        }
        if (amount.compareTo(MAX_TRANSACTION_AMOUNT) > 0) {
            throw new SecurityException("Amount exceeds maximum allowed: " + MAX_TRANSACTION_AMOUNT);
        }
        if (amount.scale() > 2) {
            throw new SecurityException("Amount must have at most 2 decimal places");
        }
    }

    public static void validateCurrency(String currency) {
        if (currency == null || !ALLOWED_CURRENCIES.contains(currency)) {
            throw new SecurityException("Currency must be one of: " + ALLOWED_CURRENCIES);
        }
    }

    public static void validateDescription(String description) {
        if (description != null && !DESCRIPTION_PATTERN.matcher(description).matches()) {
            throw new SecurityException("Description contains invalid characters or exceeds 200 chars");
        }
    }

    public static void validateTransactionId(String transactionId) {
        if (transactionId == null || !TRANSACTION_ID_PATTERN.matcher(transactionId).matches()) {
            throw new SecurityException("Transaction ID format is invalid");
        }
    }
}

